on conflict (id) do update set
  french_word = excluded.french_word,
  english_meaning = excluded.english_meaning,
  french_example = excluded.french_example,
  english_example_translation = excluded.english_example_translation,
  cefr_level = excluded.cefr_level,
  topic = excluded.topic,
  exam_type = excluded.exam_type,
  frequency_score = excluded.frequency_score,
  tags = excluded.tags,
  is_published = excluded.is_published,
  updated_at = now();

insert into public.passages (
  id,
  title,
  content,
  transcript,
  audio_url,
  type,
  skill,
  exam_type,
  cefr_level,
  topic,
  word_count,
  estimated_minutes,
  highlighted_vocabulary,
  is_published
)
values
  ('72000000-0000-4000-8000-000000000001', 'Une arrivee bien preparee a Montreal', 'Nadia arrive a Montreal dans deux semaines. Pour eviter le stress, elle a deja prepare une liste simple: confirmer son logement temporaire, imprimer ses documents, ouvrir un compte bancaire et visiter un centre d accueil francophone. Elle sait pourtant que les premieres demarches prendront du temps. En revanche, elle prefere avancer pas a pas plutot que tout faire en urgence.', null, null, 'reading', 'READING', 'BOTH', 'B1', 'IMMIGRATION', 61, 4, array['demarche','accueillir','pourtant'], true),
  ('72000000-0000-4000-8000-000000000002', 'Chercher un appartement sans se precipiter', 'Youssef visite trois appartements dans le meme quartier. Le premier est lumineux mais trop cher. Le deuxieme est moins grand, cependant il est proche du metro et du supermarche. Le troisieme semble ideal, mais le proprietaire demande plusieurs justificatifs de revenu. Finalement, Youssef comprend qu il doit comparer le loyer, le transport et les conditions du bail avant de prendre une decision.', null, null, 'reading', 'READING', 'BOTH', 'B1_PLUS', 'HOUSING', 68, 4, array['loyer','bail','justificatif'], true),
  ('72000000-0000-4000-8000-000000000003', 'Un entretien d embauche plus humain', 'Sophie postule a un poste administratif. Avant son entretien, elle relit l annonce, prepare deux exemples concrets et repete une courte presentation. Pendant la rencontre, l employeur insiste moins sur les diplomes que sur l organisation, la ponctualite et la capacite a travailler en equipe. Ainsi, Sophie realise qu une bonne preparation orale peut rassurer autant qu un cv bien ecrit.', null, null, 'reading', 'READING', 'TEF_CANADA', 'B1_PLUS', 'WORK', 64, 4, array['entretien','employeur','ainsi'], true),
  ('72000000-0000-4000-8000-000000000004', 'Prendre soin de sa sante au quotidien', 'Beaucoup de nouveaux arrivants repoussent leurs rendez-vous medicaux par manque de temps. Pourtant, une consultation precoce permet souvent d eviter un probleme plus serieux. Dans cette clinique de quartier, les patients peuvent reserver en ligne, recevoir un rappel par texto et parler a une infirmiere avant la visite. En somme, le systeme semble plus simple quand on connait les bonnes etapes.', null, null, 'reading', 'READING', 'BOTH', 'B1', 'HEALTH', 63, 4, array['rendez-vous','assurance','en somme'], true),
  ('72000000-0000-4000-8000-000000000005', 'Apprendre le francais avec regularite', 'Pour progresser en francais, Karim a choisi une methode sobre: vingt minutes de vocabulaire le matin, un texte court a midi et une activite orale le soir. Cette routine ne parait pas spectaculaire, mais elle reste durable. De plus, il note ses erreurs les plus frequentes dans un carnet. Apres deux mois, il comprend mieux les consignes d examen et ose parler plus facilement au travail.', null, null, 'reading', 'READING', 'BOTH', 'B1', 'EDUCATION', 64, 4, array['progresser','consigne','de plus'], true)
